interface SecureMediaProps {
  url: string;
  type: 'image' | 'audio' | 'pdf' | 'text' | string;
  name?: string;
}

function SecureMedia({ url, type, name }: SecureMediaProps) {
  const [signedUrl, setSignedUrl] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let isMounted = true;
    async function getSigned() {
      if (!url) return;
      try {
        const parts = url.split('/');
        const fileName = parts[parts.length - 1].split('?')[0];

        const { data, error } = await supabase.storage
          .from('chat-arquivos')
          .createSignedUrl(fileName, 3600);

        if (isMounted && !error && data) {
          setSignedUrl(data.signedUrl);
        }
      } catch (err) {
        console.error("Error creating signed URL:", err);
      } finally {
        if (isMounted) setLoading(false);
      }
    }
    getSigned();
    return () => { isMounted = false; };
  }, [url]);

  if (loading) return <div style={{ height: '100px', display: 'flex', alignItems: 'center', justifyContent: 'center', opacity: 0.3 }}><Loader2 className="animate-spin" /></div>;
  if (!signedUrl) return <div style={{ padding: '1rem', background: 'rgba(0,0,0,0.1)', fontSize: '0.8rem' }}>Arquivo indisponível ou expirado</div>;

  if (type === 'image') return <img src={signedUrl} style={{ width: '100%', display: 'block', borderRadius: '8px' }} alt={name || 'Imagem'} />;

  return (
    <a href={signedUrl} target="_blank" rel="noreferrer" style={{ 
      display: 'flex', alignItems: 'center', gap: '0.85rem', color: 'white', 
      textDecoration: 'none', fontSize: '0.85rem', padding: '0.75rem', 
      background: 'rgba(255,255,255,0.05)', borderRadius: '8px',
      border: '1px solid rgba(255,255,255,0.1)', transition: 'all 0.2s'
    }}>
      <div style={{ background: 'rgba(37, 99, 235, 0.2)', padding: '0.5rem', borderRadius: '6px' }}>
        <FileText size={18} color="#3b82f6" />
      </div>
      <div style={{ flex: 1, overflow: 'hidden' }}>
        <div style={{ fontWeight: 600, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>{name || 'Documento'}</div>
        <div style={{ fontSize: '0.65rem', opacity: 0.5 }}>Clique para abrir</div>
      </div>
    </a>
  );
}

export function LcaChat() {
  const { user, escritorioId } = useAuth();
  const navigate = useNavigate();
  const [activeModule, setActiveModule] = useState<ChatModule>('chat');
  const [activeStatus, setActiveStatus] = useState<TicketStatus>('atendimento');
  const [colaboradores, setColaboradores] = useState<Colaborador[]>([]);
  const [conversaAtivaId, setConversaAtivaId] = useState<string | null>(null);
  const [novaMensagem, setNovaMensagem] = useState('');
  const [anexo, setAnexo] = useState<File | null>(null);
  const [enviando, setEnviando] = useState(false);
  const [showEmojiPicker, setShowEmojiPicker] = useState(false);
  const emojiPickerRef = useRef<HTMLDivElement>(null);
  const isMounted = useIsMounted();
  const [searchTerm, setSearchTerm] = useState('');
  const [showNewChatPanel, setShowNewChatPanel] = useState(false);
  const [showRightPanel, setShowRightPanel] = useState(false);

  const [activeInstance, setActiveInstance] = useState<EvolutionInstance | null>(null);

  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const shouldAutoScrollRef = useRef(true);

  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const { threads, criarNovaConversa } = useChatThreads(escritorioId || undefined);
  const {
    messages, loading: loadingMessages, hasMore,
    enviarMensagem, carregarMensagens, carregarMais
  } = useChatMessages(conversaAtivaId);

  const activeEmail = user?.email;
  const activeUserId = colaboradores.find(c => c.email === activeEmail)?.id;

  useEffect(() => {
    async function init() {
      if (!escritorioId) return;

      const { data: inst } = await supabase.from('lca_chat_instancias')
        .select('*').eq('escritorio_id', escritorioId)
        .not('status', 'in', '("disconnected","close")')
        .limit(1).maybeSingle();

      if (isMounted() && inst) setActiveInstance(inst);

      const { data: cols } = await supabase
        .from('colaboradores')
        .select('*')
        .eq('escritorio_id', escritorioId)
        .order('nome');

      if (isMounted() && cols) setColaboradores(cols);
    }
    init();
  }, [escritorioId, isMounted]);

  useEffect(() => {
    if (threads.length > 0 && !conversaAtivaId && activeModule === 'chat') {
      setConversaAtivaId(threads[0].id);
    }

    return () => {
      if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
        mediaRecorderRef.current.stop();
        mediaRecorderRef.current.stream.getTracks().forEach(t => t.stop());
      }
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [threads, conversaAtivaId, activeModule]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (emojiPickerRef.current && !emojiPickerRef.current.contains(event.target as Node)) {
        setShowEmojiPicker(false);
      }
    };
    if (showEmojiPicker) {
      document.addEventListener('mousedown', handleClickOutside);
    }
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [showEmojiPicker]);

  useEffect(() => {
    if (conversaAtivaId) {
      carregarMensagens(true);
    }
  }, [conversaAtivaId, carregarMensagens]);

  const handleScroll = () => {
    if (scrollRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
      const isNearBottom = scrollHeight - scrollTop - clientHeight < 150;
      shouldAutoScrollRef.current = isNearBottom;

      if (scrollTop === 0 && hasMore && !loadingMessages) {
        carregarMais();
      }
    }
  };

  useEffect(() => {
    if (scrollRef.current && shouldAutoScrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, conversaAtivaId]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const getMimeType = () => {
        if (MediaRecorder.isTypeSupported('audio/mp4')) return 'audio/mp4';
        if (MediaRecorder.isTypeSupported('audio/aac')) return 'audio/aac';
        return 'audio/webm';
      };

      const mimeType = getMimeType();
      const recorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = recorder;
      audioChunksRef.current = [];
      recorder.ondataavailable = (e) => { if (e.data.size > 0) audioChunksRef.current.push(e.data); };
      recorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mimeType });
        const extension = mimeType.includes('mp4') ? 'mp4' : (mimeType.includes('aac') ? 'aac' : 'webm');
        const file = new File([audioBlob], `audio_${Date.now()}.${extension}`, { type: mimeType });
        if (isMounted()) setAnexo(file);
        stream.getTracks().forEach(track => track.stop());
      };
      recorder.start();
      setIsRecording(true);
      setRecordingTime(0);
      timerRef.current = setInterval(() => setRecordingTime(prev => prev + 1), 1000);
    } catch (_err) {
      toast.error('Erro ao acessar microfone');
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);
    }
  };

  const cancelRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      if (timerRef.current) clearInterval(timerRef.current);
      audioChunksRef.current = [];
      setAnexo(null);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleSendMessage = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();

    const messageText = novaMensagem.trim();
    if ((!messageText && !anexo) || !escritorioId || !conversaAtivaId || !activeUserId) return;

    if (!user?.email) {
      toast.error('Sua sessão expirou. Por favor, faça login novamente.');
      return;
    }

    setEnviando(true);
    try {
      let arquivoData: { url: string; nome: string; type: string } | undefined = undefined;
      if (anexo) {
        const fileExt = anexo.name.split('.').pop();
        const fileName = `${crypto.randomUUID()}.${fileExt}`;
        const filePath = `${fileName}`;

        const { error: uploadError } = await supabase.storage.from('chat-arquivos').upload(filePath, anexo);
        if (uploadError) throw new Error('Falha no upload do arquivo');

        const { data: urlData } = supabase.storage.from('chat-arquivos').getPublicUrl(filePath);
        arquivoData = { url: urlData.publicUrl, nome: anexo.name, type: anexo.type };
      }

      const tMidia = anexo?.type.startsWith('audio/') ? 'audio' : (anexo?.type.startsWith('image/') ? 'image' : (anexo?.type === 'application/pdf' ? 'pdf' : 'text'));

      await enviarMensagem({
        escritorioId,
        autorId: activeUserId,
        autorNome: user?.user_metadata?.nome || user.email.split('@')[0] || 'Usuário',
        autorEmail: user.email,
        mensagem: messageText,
        tipoMidia: tMidia,
        arquivo: arquivoData
      });

      try {
        const inst = activeInstance;
        const activeThread = threads.find(t => t.id === conversaAtivaId);

        if (inst && activeThread) {
          const targetId = activeThread.participantes.find(p => p !== activeUserId);
          if (targetId) {
            const { data: contato } = await supabase.from('contatos').select('telefone').eq('id', targetId).maybeSingle();
            if (contato && contato.telefone) {
               const serverUrl = inst.config?.server_url || localStorage.getItem('evol_url') || '';
               const globalKey = inst.config?.global_key || localStorage.getItem('evol_key') || inst.apikey_instancia || '';

               if (serverUrl && globalKey) {
                 if (arquivoData && anexo) {
                   const evMidia = anexo.type.startsWith('audio/') ? 'audio' : (anexo.type.startsWith('image/') ? 'image' : 'document');
                   await evolutionApi.sendMedia(inst.nome_instancia, contato.telefone, arquivoData.url, evMidia, serverUrl, globalKey);
                 }
                 if (messageText) {
                   await evolutionApi.sendText(inst.nome_instancia, contato.telefone, messageText, serverUrl, globalKey);
                 }
               }
            }
          }
        }
      } catch (evolError) {
        console.error("Erro Evolution API:", evolError);
      }

      if (isMounted()) {
        setNovaMensagem('');
        setAnexo(null);
      }
    } catch {
      toast.error('Erro ao enviar');
    } finally {
      if (isMounted()) setEnviando(false);
    }
  };

  const handleStartNewChat = async (targetColab: Colaborador) => {
    if (!escritorioId || !activeUserId) return;
    const existing = threads.find(t => t.tipo === 'direta' && t.participantes.includes(targetColab.id) && t.participantes.includes(activeUserId));
    if (existing) {
      setConversaAtivaId(existing.id);
      setShowNewChatPanel(false);
      return;
    }
    const newChat = await criarNovaConversa({ tipo: 'direta', nome: targetColab.nome, participantes: [activeUserId, targetColab.id], escritorio_id: escritorioId });
    if (newChat && isMounted()) {
      setConversaAtivaId(newChat.id);
      setShowNewChatPanel(false);
    }
  };

  const SidebarItem = ({ id, icon: Icon, label }: { id: ChatModule, icon: React.ElementType, label: string }) => (
    <button
      onClick={() => setActiveModule(id)}
      style={{
        width: '100%', padding: '0.85rem', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.25rem',
        background: activeModule === id ? COLORS.sidebarItem : 'transparent',
        border: 'none', color: activeModule === id ? COLORS.text : COLORS.textMuted,
        cursor: 'pointer', borderRadius: '12px', transition: 'all 0.2s', position: 'relative'
      }}
    >
      {activeModule === id && (
        <motion.div layoutId="active-nav" style={{ position: 'absolute', left: 0, width: '4px', height: '60%', background: COLORS.primary, borderRadius: '0 4px 4px 0' }} />
      )}
      <Icon size={22} />
      <span style={{ fontSize: '0.65rem', fontWeight: 600 }}>{label}</span>
    </button>
  );

  const Avatar = ({ src, name, size = 32 }: { src?: string, name: string, size?: number }) => {
    if (src) return <img src={src} alt={name} style={{ width: `${size}px`, height: `${size}px`, borderRadius: '30%', objectFit: 'cover' }} />;
    const initials = name.split(' ').map(n => n[0]).join('').substring(0, 2).toUpperCase();
    return (
      <div style={{
        width: `${size}px`, height: `${size}px`, borderRadius: '30%',
        background: 'linear-gradient(135deg, #2563eb 0%, #3b82f6 100%)',
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        color: 'white', fontSize: size > 32 ? '0.9rem' : '0.75rem', fontWeight: 600
      }}>
        {initials || '?'}
      </div>
    );
  };

  return (
    <div style={{
      display: 'flex', height: '100vh', width: '100vw', overflow: 'hidden',
      background: COLORS.bg, color: COLORS.text, margin: 0, position: 'fixed', top: 0, left: 0
    }}>

      <div style={{
        width: '72px', background: COLORS.sidebar, display: 'flex', flexDirection: 'column',
        alignItems: 'center', padding: '1.25rem 0', gap: '1.5rem', borderRight: `1px solid ${COLORS.border}`
      }}>
        <div
          onClick={() => navigate('/')}
          style={{ width: '44px', height: '44px', background: COLORS.primary, borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', marginBottom: '1rem' }}
        >
          <LayoutGrid size={24} color="white" />
        </div>

        <SidebarItem id="chat" icon={MessageSquare} label="Chat" />
        <SidebarItem id="kanban" icon={Kanban} label="Kanban" />
        <SidebarItem id="crm" icon={Database} label="Contatos" />
        <SidebarItem id="fluxos" icon={Layers} label="Fluxos" />
        <SidebarItem id="relatorios" icon={BarChart3} label="Insights" />
        <SidebarItem id="configuracoes" icon={Settings} label="Conexões" />

        <div style={{ marginTop: 'auto', display: 'flex', flexDirection: 'column', gap: '1rem', alignItems: 'center' }}>
          <Avatar name={user?.user_metadata?.nome || 'Eu'} size={36} />
        </div>
      </div>

      <div style={{ flex: 1, display: 'flex', overflow: 'hidden' }}>

        {activeModule === 'chat' && (
          <div style={{ display: 'flex', flex: 1, overflow: 'hidden' }}>
            <div style={{ width: '310px', display: 'flex', flexDirection: 'column', background: COLORS.sidebarItem, borderRight: `1px solid ${COLORS.border}` }}>
              <div style={{ padding: '1.5rem 1.25rem 1rem 1.25rem' }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.5rem' }}>
                  <h2 style={{ fontSize: '1.25rem', fontWeight: 800, margin: 0, color: 'white', letterSpacing: '-0.02em' }}>Atendimentos</h2>
                  <button
                    onClick={() => setShowNewChatPanel(true)}
                    style={{ background: COLORS.primary, border: 'none', borderRadius: '10px', color: 'white', width: '32px', height: '32px', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                  >
                    <Plus size={18} />
                  </button>
                </div>

                <div style={{ display: 'flex', background: 'rgba(0,0,0,0.2)', padding: '4px', borderRadius: '12px', marginBottom: '1.25rem', border: '1px solid rgba(255,255,255,0.05)' }}>
                  {(['aguardando', 'atendimento', 'finalizado'] as TicketStatus[]).map(status => (
                    <button
                      key={status}
                      onClick={() => setActiveStatus(status)}
                      style={{
                        flex: 1, padding: '10px 4px', borderRadius: '8px', fontSize: '0.75rem', fontWeight: 700, border: 'none',
                        background: activeStatus === status ? COLORS.primary : 'transparent',
                        color: activeStatus === status ? 'white' : 'rgba(255,255,255,0.4)',
                        cursor: 'pointer', textTransform: 'uppercase', transition: 'all 0.3s'
                      }}
                    >
                      {status === 'aguardando' ? 'Fila' : status === 'atendimento' ? 'Chat' : 'Fim'}
                    </button>
                  ))}
                </div>

                <div style={{ position: 'relative' }}>
                  <Search size={16} style={{ position: 'absolute', left: '12px', top: '50%', transform: 'translateY(-50%)', opacity: 0.3, color: 'white' }} />
                  <input 
                    type="text" 
                    placeholder="Pesquisar..." 
                    style={{ 
                      width: '100%', background: 'rgba(0,0,0,0.2)', border: '1px solid rgba(255,255,255,0.05)', 
                      borderRadius: '10px', padding: '10px 10px 10px 38px', color: 'white', fontSize: '0.9rem',
                      outline: 'none'
                    }}
                    value={searchTerm} onChange={e => setSearchTerm(e.target.value)}
                  />
                </div>
              </div>

              <div style={{ flex: 1, overflowY: 'auto', padding: '0.5rem 0.75rem' }} className="custom-scrollbar">
                {threads
                  .filter(t => t.nome?.toLowerCase().includes(searchTerm.toLowerCase()))
                  .filter(t => activeStatus === 'atendimento' || (activeStatus === 'aguardando' && t.tipo === 'equipe')) 
                  .map(t => (
                  <button
                    key={t.id} onClick={() => setConversaAtivaId(t.id)}
                    style={{
                      width: '100%', display: 'flex', alignItems: 'center', gap: '0.85rem', padding: '1rem',
                      background: conversaAtivaId === t.id ? 'rgba(37, 99, 235, 0.1)' : 'transparent',
                      border: 'none', cursor: 'pointer', textAlign: 'left', borderRadius: '12px',
                      marginBottom: '4px', transition: 'all 0.2s',
                      borderLeft: conversaAtivaId === t.id ? `4px solid ${COLORS.primary}` : '4px solid transparent'
                    }}
                  >
                    <Avatar name={t.nome || 'G'} size={42} />
                    <div style={{ flex: 1, overflow: 'hidden' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2px' }}>
                        <span style={{ fontWeight: 600, fontSize: '0.85rem', color: COLORS.text }}>{t.nome}</span>
                        <span style={{ fontSize: '0.65rem', opacity: 0.5 }}>{new Date(t.ultima_mensagem_data).toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}</span>
                      </div>
                      <p style={{ margin: 0, fontSize: '0.75rem', color: COLORS.textMuted, whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                        {t.tipo === 'equipe' ? 'Ticket de Escritório' : 'Conversa Privada'}
                      </p>
                    </div>
                  </button>
                ))}
              </div>
            </div>

            <div style={{ flex: 1, display: 'flex', flexDirection: 'column', background: COLORS.bg }}>
               {!conversaAtivaId ? (
                 <div style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', opacity: 0.3 }}>
                   <MessageSquare size={80} style={{ marginBottom: '1.5rem', color: 'white' }} />
                   <h2 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'white' }}>LCA Chat Beta</h2>
                   <p style={{ color: 'white' }}>Selecione um contato para começar a atender</p>
                 </div>
               ) : (
                 <>
                  <div style={{ padding: '0.85rem 1.5rem', borderBottom: `1px solid ${COLORS.border}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between', background: COLORS.sidebarItem }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', flex: 1 }}>
                      <Avatar name={threads.find(t=>t.id===conversaAtivaId)?.nome || ''} size={40} />
                      <div style={{ flex: 1 }}>
                        <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 700 }}>{threads.find(t=>t.id===conversaAtivaId)?.nome}</h3>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                          <span style={{ fontSize: '0.7rem', color: COLORS.success, fontWeight: 600 }}>● Online</span>
                          <span style={{ fontSize: '0.7rem', opacity: 0.4 }}>•</span>
                          <span style={{ fontSize: '0.7rem', color: COLORS.textMuted }}>Setor: Comercial</span>
                        </div>
                      </div>
                    </div>

                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                      {activeStatus === 'aguardando' && (
                        <button 
                          onClick={() => setActiveStatus('atendimento')}
                          style={{
                            padding: '6px 16px', background: COLORS.success, border: 'none', borderRadius: '8px',
                            color: 'white', fontWeight: 700, cursor: 'pointer', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '6px'
                          }}
                        >
                          <Play size={14} /> ACEITAR
                        </button>
                      )}

                      {activeStatus === 'atendimento' && (
                        <>
                          <button 
                            style={{ background: 'transparent', border: `1px solid ${COLORS.border}`, color: COLORS.text, padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '6px' }}
                          >
                            <ArrowRight size={14} /> TRANSFERIR
                          </button>
                          <button 
                            onClick={() => setActiveStatus('finalizado')}
                            style={{ background: COLORS.danger, border: 'none', color: 'white', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontSize: '0.8rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '6px' }}
                          >
                            <CheckCircle size={14} /> FINALIZAR
                          </button>
                        </>
                      )}

                      <button onClick={()=>setShowRightPanel(!showRightPanel)} style={{ background: 'transparent', border: 'none', color: COLORS.textMuted, cursor: 'pointer', padding: '4px' }}>
                        <Users size={20}/>
                      </button>
                    </div>
                  </div>

                  <div 
                    ref={scrollRef} 
                    onScroll={handleScroll}
                    style={{ flex: 1, overflowY: 'auto', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1.25rem' }}
                  >
                    {hasMore && (
                      <button 
                        onClick={carregarMais}
                        className="btn-outline flex-center"
                        style={{ 
                          alignSelf: 'center', fontSize: '0.75rem', gap: '8px', padding: '6px 16px',
                          color: COLORS.primary, borderColor: 'rgba(37,99,235,0.2)', marginBottom: '1rem'
                        }}
                      >
                        {loadingMessages ? <Loader2 className="animate-spin" size={14}/> : 'Carregar mensagens anteriores'}
                      </button>
                    )}
                    {messages.map((msg) => {
                      const isMine = msg.autor_email === activeEmail;
                      return (
                        <div key={msg.id} style={{ alignSelf: isMine ? 'flex-end' : 'flex-start', maxWidth: '70%' }}>
                          <div style={{ 
                            background: isMine ? COLORS.primary : COLORS.card, padding: '0.75rem 1rem', borderRadius: isMine ? '14px 14px 0 14px' : '14px 14px 14px 0',
                            boxShadow: '0 4px 15px rgba(0,0,0,0.1)', border: isMine ? 'none' : `1px solid ${COLORS.border}`
                          }}>
                            {msg.arquivo_url && (
                              <div style={{ marginBottom: '0.5rem', borderRadius: '8px', overflow: 'hidden' }}>
                                <SecureMedia 
                                  url={msg.arquivo_url} 
                                  type={msg.tipo_midia as 'image' | 'audio' | 'pdf' | 'text'} 
                                  name={msg.arquivo_nome} 
                                />
                              </div>
                            )}
                            <p style={{ margin: 0, fontSize: '0.9rem', lineHeight: 1.5 }}>{msg.mensagem}</p>
                            <span style={{ fontSize: '0.6rem', opacity: 0.4, display: 'block', textAlign: 'right', marginTop: '4px' }}>
                              {new Date(msg.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                            </span>
                          </div>
                        </div>
                      );
                    })}
                  </div>

                  <div style={{ padding: '1.25rem', background: COLORS.sidebarItem, borderTop: `1px solid ${COLORS.border}`, position: 'relative' }}>

                    <AnimatePresence>
                      {showEmojiPicker && (
                        <motion.div 
                          initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 20 }}
                          style={{ position: 'absolute', bottom: '80px', left: '1rem', zIndex: 100 }}
                          ref={emojiPickerRef}
                        >
                          <EmojiPicker 
                            theme={Theme.DARK} 
                            onEmojiClick={(e) => setNovaMensagem(prev => prev + e.emoji)}
                          />
                        </motion.div>
                      )}
                    </AnimatePresence>

                    <form onSubmit={handleSendMessage} style={{ display: 'flex', gap: '0.75rem', alignItems: 'center' }}>
                      <button type="button" onClick={() => setShowEmojiPicker(!showEmojiPicker)} style={{ background: COLORS.bg, border: 'none', color: COLORS.textMuted, width: '40px', height: '40px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                        <span style={{ fontSize: '1.2rem' }}>😀</span>
                      </button>
                      <button type="button" onClick={() => fileInputRef.current?.click()} style={{ background: COLORS.bg, border: 'none', color: COLORS.textMuted, width: '40px', height: '40px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
                        <Paperclip size={20} />
                      </button>
                      <input type="file" ref={fileInputRef} style={{ display: 'none' }} onChange={e => { if (e.target.files) setAnexo(e.target.files[0]); }} />

                      <div style={{ flex: 1, position: 'relative' }}>
                        {isRecording ? (
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', padding: '0.65rem 1rem', background: '#7f1d1d', borderRadius: '10px' }}>
                            <div style={{ width: '8px', height: '8px', background: 'red', borderRadius: '50%' }} />
                            <span style={{ fontSize: '0.85rem', fontWeight: 700 }}>GRAVANDO {formatTime(recordingTime)}</span>
                            <button onClick={cancelRecording} style={{ marginLeft: 'auto', background: 'none', border: 'none', color: 'white' }}><Trash2 size={18}/></button>
                          </div>
                        ) : (
                          <input 
                            placeholder="Mande uma mensagem..." 
                            style={{ width: '100%', padding: '0.65rem 1rem', background: COLORS.bg, border: 'none', borderRadius: '10px', color: 'white', outline: 'none' }}
                            value={novaMensagem} onChange={e=>setNovaMensagem(e.target.value)}
                          />
                        )}
                      </div>

                      {isRecording ? (
                        <button onClick={stopRecording} type="button" style={{ background: COLORS.danger, border: 'none', color: 'white', width: '40px', height: '40px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                          <StopCircle size={20} />
                        </button>
                      ) : (
                        novaMensagem.trim() || anexo ? (
                          <button type="submit" disabled={enviando} style={{ background: COLORS.primary, border: 'none', color: 'white', width: '40px', height: '40px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <Send size={18} />
                          </button>
                        ) : (
                          <button onClick={startRecording} type="button" style={{ background: COLORS.bg, border: 'none', color: COLORS.textMuted, width: '40px', height: '40px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                            <Mic size={20} />
                          </button>
                        )
                      )}
                    </form>
                  </div>
                 </>
               )}
            </div>

            <AnimatePresence>
              {showRightPanel && (
                <motion.div initial={{width:0}} animate={{width:300}} exit={{width:0}} style={{ background: COLORS.sidebar, borderLeft: `1px solid ${COLORS.border}`, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
                   <div style={{ padding: '2rem', textAlign: 'center' }}>
                     <Avatar name={threads.find(t=>t.id===conversaAtivaId)?.nome || ''} size={100} />
                     <h3 style={{ marginTop: '1rem' }}>{threads.find(t=>t.id===conversaAtivaId)?.nome}</h3>
                     <p style={{ fontSize: '0.8rem', color: COLORS.textMuted }}>Setor: Atendimento Comercial</p>
                   </div>
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        )}

        <div style={{ flex: 1, display: activeModule === 'kanban' ? 'block' : 'none', height: '100%', background: COLORS.bg, overflowY: 'auto' }}>
          <ChatKanban dashboardMode />
        </div>
        <div style={{ flex: 1, display: activeModule === 'crm' ? 'block' : 'none', height: '100%', background: COLORS.bg, overflowY: 'auto' }}>
          <ContatosCRM dashboardMode />
        </div>
        <div style={{ flex: 1, display: activeModule === 'fluxos' ? 'block' : 'none', height: '100%', background: COLORS.bg }}>
          <FluxoChatbot dashboardMode />
        </div>
        <div style={{ flex: 1, display: activeModule === 'configuracoes' ? 'block' : 'none', height: '100%', background: COLORS.bg, overflowY: 'auto' }}>
          <ConnectionPanel dashboardMode />
        </div>
        <div style={{ flex: 1, display: activeModule === 'relatorios' ? 'block' : 'none', height: '100%', background: COLORS.bg, overflowY: 'auto' }}>
          <RelatorioChat dashboardMode />
        </div>

      </div>

      <AnimatePresence>
        {showNewChatPanel && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.8)', zIndex: 2000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            onClick={() => setShowNewChatPanel(false)}
          >
            <motion.div 
              onClick={e=>e.stopPropagation()}
              initial={{ scale: 0.9 }} animate={{ scale: 1 }}
              style={{ width: '400px', background: COLORS.card, borderRadius: '20px', padding: '1.5rem', border: `1px solid ${COLORS.border}` }}
            >
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1.5rem' }}>
                <h3 style={{ margin: 0 }}>Iniciar Conversa</h3>
                <X size={20} style={{ cursor: 'pointer' }} onClick={()=>setShowNewChatPanel(false)} />
              </div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxHeight: '400px', overflowY: 'auto' }}>
                {colaboradores.filter(c => c.email !== activeEmail).map(c => (
                  <button key={c.id} onClick={()=>handleStartNewChat(c)} style={{ display: 'flex', alignItems: 'center', gap: '1rem', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', border: 'none', borderRadius: '12px', color: 'white', cursor: 'pointer', textAlign: 'left' }}>
                    <Avatar src={c.foto_url} name={c.nome} size={40} />
                    <div>
                      <div style={{ fontWeight: 600 }}>{c.nome}</div>
                      <div style={{ fontSize: '0.75rem', opacity: 0.5 }}>{c.email}</div>
                    </div>
                  </button>
                ))}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.1); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(255,255,255,0.2); }
      `}</style>
    </div>
  );
}

export default LcaChat;

import { useState, useEffect } from 'react';
import { Plus, CheckCircle2, Circle, Trash2, Edit2, User, Search, LayoutList, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';
import { useApp } from '../contexts/AppContext';
import { supabase } from '../lib/supabase';

interface Tarefa {
  id: string;
  titulo: string;
  descricao?: string;
  data_limite: string;
  responsavel_id: string; // Responsible (Principal)
  colaboradores_adicionais?: string[]; // Array of IDs
  concluida: boolean;
  prioridade: 'alta' | 'media' | 'baixa';
  criado_por_id?: string;
  colaboradores?: { nome: string }; // For joined queries
}

interface Colaborador {
  id: string;
  nome: string;
}

export function Organograma() {
  const [tarefas, setTarefas] = useState<Tarefa[]>([]);
  const [colaboradores, setColaboradores] = useState<Colaborador[]>([]);
  const [showAdd, setShowAdd] = useState(false);
  const [tarefaEditando, setTarefaEditando] = useState<Tarefa | null>(null);
  const { setIsLoading, reportError } = useApp();
  const [filtro, setFiltro] = useState('');
  const [filtroResponsavel, setFiltroResponsavel] = useState('todos');

  const [novaTarefa, setNovaTarefa] = useState({
    titulo: '',
    descricao: '',
    data_limite: new Date().toISOString().slice(0, 16), // datetime-local format
    responsavel_id: 'Admin',
    colaboradores_adicionais: [] as string[],
    prioridade: 'media' as 'alta' | 'media' | 'baixa'
  });

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    setIsLoading(true);
    try {
      const [demandasRes, colabRes] = await Promise.all([
        supabase.from('demandas').select('*, colaboradores(nome)').order('data_limite', { ascending: true }),
        supabase.from('colaboradores').select('id, nome')
      ]);

      if (demandasRes.error) throw demandasRes.error;
      if (colabRes.error) throw colabRes.error;

      setTarefas(demandasRes.data || []);
      setColaboradores(colabRes.data || []);
    } catch (err: any) {
      reportError('Erro Organograma', `Falha ao carregar as demandas: ${err.message}`);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAdd = async () => {
    if (!novaTarefa.titulo) return toast.error('O título é obrigatório.');

    // Tratamento caso 'Admin' seja selecionado (null ID database)
    const respId = novaTarefa.responsavel_id === 'Admin' ? null : novaTarefa.responsavel_id;

    try {
      const payload = {
        titulo: novaTarefa.titulo,
        descricao: novaTarefa.descricao,
        data_limite: novaTarefa.data_limite,
        responsavel_id: respId,
        colaboradores_adicionais: novaTarefa.colaboradores_adicionais,
        prioridade: novaTarefa.prioridade,
        concluida: false
      };

      const { error } = await supabase.from('demandas').insert([payload]);
      if (error) throw error;

      toast.success('Tarefa adicionada com sucesso');
      setShowAdd(false);
      setNovaTarefa({ titulo: '', descricao: '', data_limite: new Date().toISOString().slice(0, 16), responsavel_id: colaboradores[0]?.id || 'Admin', colaboradores_adicionais: [], prioridade: 'media' });
      carregarDados();
    } catch (error: any) {
      console.error(error);
      toast.error('Erro ao adicionar tarefa.');
    }
  };

  const handleEdit = async () => {
    if (!tarefaEditando || !tarefaEditando.titulo) return toast.error('O título é obrigatório.');

    const respId = tarefaEditando.responsavel_id === 'Admin' ? null : tarefaEditando.responsavel_id;

    try {
      const payload = {
        titulo: tarefaEditando.titulo,
        descricao: tarefaEditando.descricao,
        data_limite: tarefaEditando.data_limite,
        responsavel_id: respId,
        colaboradores_adicionais: tarefaEditando.colaboradores_adicionais || [],
        prioridade: tarefaEditando.prioridade,
      };

      const { error } = await supabase.from('demandas').update(payload).eq('id', tarefaEditando.id);
      if (error) throw error;

      toast.success('Tarefa atualizada com sucesso');
      setTarefaEditando(null);
      carregarDados();
    } catch (error: any) {
      console.error(error);
      toast.error('Erro ao atualizar tarefa.');
    }
  };

  const toggleTarefa = async (t: Tarefa) => {
    try {
      const { error } = await supabase
        .from('demandas')
        .update({ concluida: !t.concluida, data_conclusao: !t.concluida ? new Date().toISOString() : null })
        .eq('id', t.id);

      if (error) throw error;
      carregarDados();
    } catch (error: any) {
      toast.error('Erro ao atualizar status.');
    }
  };

  const removerTarefa = async (id: string) => {
    if (confirm('Deseja excluir esta tarefa?')) {
      try {
        const { error } = await supabase.from('demandas').delete().eq('id', id);
        if (error) throw error;
        toast.success('Tarefa removida');
        carregarDados();
      } catch (error: any) {
        toast.error('Erro ao remover tarefa');
      }
    }
  };

  const getNomeResponsavel = (t: Tarefa) => t.colaboradores?.nome || 'Admin';

  const tarefasFiltradas = tarefas.filter(t => 
    getNomeResponsavel(t).toLowerCase().includes(filtro.toLowerCase())
  ).filter(t => {
    if (filtroResponsavel === 'todos') return true;
    if (filtroResponsavel === 'Admin') return t.responsavel_id === null;
    return t.responsavel_id === filtroResponsavel || t.colaboradores_adicionais?.includes(filtroResponsavel);
  });

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="animate-in">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '2.5rem' }}>
        <div>
          <h1 className="text-serif" style={{ fontSize: '2.5rem' }}>Organograma & Tarefas</h1>
          <p className="text-muted">Acompanhamento de demandas e responsabilidades do escritório.</p>
        </div>
        <button onClick={() => setShowAdd(true)} className="btn-primary flex-center" style={{ gap: '0.5rem' }}>
          <Plus size={18} /> Nova Tarefa
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 350px', gap: '2rem', alignItems: 'start' }}>
        <div className="glass-panel" style={{ padding: '2rem' }}>
          <div style={{ display: 'flex', gap: '1rem', marginBottom: '2rem' }}>
            <div style={{ position: 'relative', flex: 1 }}>
              <Search size={18} style={{ position: 'absolute', left: '1rem', top: '50%', transform: 'translateY(-50%)', opacity: 0.4 }} />
              <input 
                type="text" 
                placeholder="Pesquisar tarefas..." 
                className="input-field" 
                style={{ paddingLeft: '3rem' }} 
                value={filtro}
                onChange={e => setFiltro(e.target.value)}
              />
            </div>
            <select 
              className="input-field" 
              style={{ maxWidth: '200px' }}
              value={filtroResponsavel}
              onChange={e => setFiltroResponsavel(e.target.value)}
            >
              <option value="todos">Todos Responsáveis</option>
              <option value="Admin">Admin</option>
              {colaboradores.map(c => <option key={c.id} value={c.id}>{c.nome}</option>)}
            </select>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
            {tarefasFiltradas.length > 0 ? (
              tarefasFiltradas.sort((a,b) => {
                if (a.concluida !== b.concluida) return Number(a.concluida) - Number(b.concluida);
                return new Date(a.data_limite).getTime() - new Date(b.data_limite).getTime();
              }).map(t => (
                <div key={t.id} style={{ 
                  display: 'flex', alignItems: 'flex-start', gap: '1rem', padding: '1rem', 
                  background: t.concluida ? 'rgba(0,0,0,0.01)' : 'white', 
                  border: '1px solid var(--color-border)', borderRadius: '12px',
                  opacity: t.concluida ? 0.6 : 1, transition: 'all 0.2s'
                }}>
                  <button onClick={() => toggleTarefa(t)} style={{ background: 'transparent', border: 'none', cursor: 'pointer', padding: 0, marginTop: '2px' }}>
                    {t.concluida ? <CheckCircle2 size={22} color="var(--color-success)" /> : <Circle size={22} color="var(--color-border)" />}
                  </button>
                  <div style={{ flex: 1 }}>
                    <h4 style={{ margin: 0, textDecoration: t.concluida ? 'line-through' : 'none' }}>{t.titulo}</h4>
                    {t.descricao && <p className="text-muted" style={{ fontSize: '0.85rem', margin: '0.25rem 0' }}>{t.descricao}</p>}
                    <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                      <span className="flex-center" style={{ gap: '0.25rem', fontSize: '0.7rem' }}>
                        <User size={12} /> {getNomeResponsavel(t)}
                        {t.colaboradores_adicionais && t.colaboradores_adicionais.length > 0 && (
                          <span style={{ marginLeft: '4px', opacity: 0.6 }}>+ {t.colaboradores_adicionais.length}</span>
                        )}
                      </span>
                      <span style={{ 
                        fontSize: '0.65rem', padding: '0.1rem 0.4rem', borderRadius: '4px', 
                        background: t.prioridade === 'alta' ? 'var(--color-danger-bg)' : 'rgba(0,0,0,0.05)',
                        color: t.prioridade === 'alta' ? 'var(--color-danger)' : 'inherit'
                      }}>{t.prioridade.toUpperCase()}</span>
                    </div>
                  </div>
                  <div style={{ display: 'flex', gap: '0.25rem' }}>
                    <button onClick={() => setTarefaEditando(t)} className="btn-outline" style={{ border: 'none', padding: '0.4rem', color: 'var(--color-warning)' }}><Edit2 size={16}/></button>
                    <button onClick={() => removerTarefa(t.id)} className="btn-outline" style={{ border: 'none', padding: '0.4rem', color: 'var(--color-danger)' }}><Trash2 size={16}/></button>
                  </div>
                </div>
              ))
            ) : (
              <div style={{ textAlign: 'center', padding: '4rem', color: 'var(--color-text-muted)' }}>
                <LayoutList size={48} style={{ margin: '0 auto 1rem', opacity: 0.2 }} />
                <p>Nenhuma tarefa ativa. Clique em "Nova Tarefa" para começar.</p>
              </div>
            )}
          </div>
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
          <div className="glass-panel" style={{ padding: '1.5rem' }}>
            <h4 className="text-serif" style={{ marginTop: 0 }}>Produtividade</h4>
            <div style={{ marginTop: '1rem', display: 'grid', gap: '1rem' }}>
