                                  const ids = e.target.checked 
                                    ? [...(tarefaEditando.colaboradores_adicionais || []), c.id]
                                    : (tarefaEditando.colaboradores_adicionais || []).filter(id => id !== c.id);
                                  setTarefaEditando({...tarefaEditando, colaboradores_adicionais: ids});
                                }}
                              />
                              {c.nome.split(' ')[0]}
                            </label>
                          ))}
                        </div>
