        )}
      </AnimatePresence>
    </motion.div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useApp } from '../contexts/AppContext';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  LogIn, DollarSign, TrendingUp, LogOut, 
  CheckCircle2, Circle, ListTodo, History, FileText,
  Calendar as CalendarIcon
} from 'lucide-react';
import { pageVariants, pageTransition } from '../lib/animations';
import { toast } from 'sonner';
import { supabase } from '../lib/supabase';
import { CalendarGrid } from '../components/Agenda/CalendarGrid';
import { Tarefa, GoogleEvent, Distribuicao } from '../types';



export function PortalColaborador() {
  const [session, setSession] = useState<{ id: string; nome: string; OAB: string; email?: string; podeEditarTarefas?: boolean; foto_url?: string; escritorio_id?: string } | null>(null);
  const [loginInput, setLoginInput] = useState('');
  const [passwordInput, setPasswordInput] = useState('');
  const [distribuicoes, setDistribuicoes] = useState<Distribuicao[]>([]);
  const { setIsLoading, reportError } = useApp();
  const [demandas, setDemandas] = useState<Tarefa[]>([]); 
  const [googleEvents, setGoogleEvents] = useState<GoogleEvent[]>([]);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [activeTab, setActiveTab] = useState<'financeiro' | 'agenda'>('financeiro');
  const [currentDate, setCurrentDate] = useState(new Date());
  const [expandedTask, setExpandedTask] = useState<string | null>(null);

  const carregarDadosSessao = useCallback(async (idColab: string, nomeColabOverride?: string, escritorioIdOverride?: string) => {
    setIsLoading(true);
    try {
        const colabNome = nomeColabOverride || session?.nome || '';
        const eid = escritorioIdOverride || session?.escritorio_id;

        if (!eid) return;

        const [transRes, tarefasRes, eventosRes] = await Promise.all([
          supabase.from('transacoes')
            .select('*')
            .eq('escritorio_id', eid)
            .or(`responsavel.eq.${idColab},responsavel.eq."${colabNome}"`),
          supabase.from('demandas')
            .select('*, colaboradores(nome)')
            .eq('escritorio_id', eid),
          supabase.from('eventos_externos')
            .select('*')
            .eq('escritorio_id', eid)
        ]);

        if (transRes.error) throw transRes.error;
        if (tarefasRes.error) throw tarefasRes.error;
        if (eventosRes.error) throw eventosRes.error;

        setDistribuicoes((transRes.data || []).map((t: any) => ({
            id: t.id,
            processo: t.processos?.numero_processo || t.referencia || 'N/A',
            honorario: t.valor || 0,
            percentual: t.percentual || 0,
            data: t.data,
            status: t.status,
            baseLiquida: t.base_calculo || t.valor,
            valor: t.valor || 0,
            referencia: t.referencia || 'Distribuição'
        })));

        const userTasks = (tarefasRes.data || []).filter((t: any) => {
            const currentIdStr = idColab.toString();
            const currentName = nomeColabOverride || session?.nome;

            const isResp = (t.responsavel_id?.toString() === currentIdStr) || 
                          (t.colaboradores?.nome === currentName);

            let isAdic = false;
            if (t.colaboradores_adicionais) {
              const adic = t.colaboradores_adicionais;
              if (Array.isArray(adic)) {
                isAdic = adic.some((id: any) => id?.toString() === currentIdStr);
              } else if (typeof adic === 'string') {
                try {
                  const parsed = JSON.parse(adic);
                  if (Array.isArray(parsed)) {
                    isAdic = parsed.some((id: any) => id?.toString() === currentIdStr);
                  } else {
                    isAdic = adic.includes(currentIdStr) || adic.includes(currentName || '');
                  }
                } catch {
                  isAdic = adic.includes(currentIdStr) || adic.includes(currentName || '');
                }
              }
            }
            return isResp || isAdic;
        }) as Tarefa[];
        setDemandas(userTasks);

        setGoogleEvents((eventosRes.data || []).map((e: any) => ({
            id: e.google_id || e.id,
            summary: e.titulo,
            start: { dateTime: e.data, date: e.data.split('T')[0] },
            end: { dateTime: e.data, date: e.data.split('T')[0] },
            description: e.descricao
        })));

    } catch (error: unknown) {
        const errorMessage = error instanceof Error 
            ? (error.message.includes('PGRST') ? 'Não foi possível ler os dados do banco.' : error.message)
            : 'Houve um erro de comunicação.';
        reportError('Erro Portal', `Não foi possível carregar os dados do seu portal: ${errorMessage}`);
    } finally {
        setIsLoading(false);
    }
  }, [setIsLoading, reportError, session?.nome, session?.escritorio_id]);

  useEffect(() => {
    const savedSession = sessionStorage.getItem('lca_portal_session');
    if (savedSession) {
      const sess = JSON.parse(savedSession);
      setSession(sess);
      carregarDadosSessao(sess.id, sess.nome, sess.escritorio_id);
    }
  }, [carregarDadosSessao]);

  useEffect(() => {
    if (session) {
      carregarDadosSessao(session.id);

      const channel = supabase
        .channel('portal-demandas-changes')
        .on(
          'postgres_changes',
          { event: '*', schema: 'public', table: 'demandas' },
          () => {
             carregarDadosSessao(session.id);
          }
        )
        .subscribe();

      return () => {
        supabase.removeChannel(channel);
      };
    }
  }, [session, carregarDadosSessao]);

  const toggleTarefa = async (id: string, currentStatus: boolean, escritorioIdOverride?: string) => {
    try {
      const eid = escritorioIdOverride || session?.escritorio_id;
      if (!eid) throw new Error('Escritório não identificado.');

      const { error } = await supabase
        .from('demandas')
        .update({ concluida: !currentStatus })
        .eq('id', id)
        .eq('escritorio_id', eid);

      if (error) throw error;

      setDemandas(prev => prev.map(t => t.id === id ? { ...t, concluida: !currentStatus } : t));
    } catch (error: any) {
      reportError('Erro Tarefa', `Falha ao atualizar status: ${error.message}`);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    const emailInput = loginInput.trim().toLowerCase();
    const passInput = passwordInput.trim();

    if (!emailInput || !passInput) {
      return toast.error('Preencha e-mail e senha.');
    }

    setIsLoggingIn(true);
    try {
      // Manual Credential Check (Independent of Supabase Auth)
      const { data: colab, error: colabErr } = await supabase
        .from('colaboradores')
        .select('*')
        .eq('email', emailInput)
        .eq('senha_portal', passInput)
        .maybeSingle();

      if (colabErr || !colab) {
        throw new Error('E-mail ou senha do portal incorretos.');
      }

      const sessionData = { 
        id: colab.id, 
        nome: colab.nome, 
        email: colab.email, 
        OAB: colab.OAB || '', 
        podeEditarTarefas: colab.pode_editar_tarefas,
        foto_url: colab.foto_url,
        escritorio_id: colab.escritorio_id
      };

      setSession(sessionData);
      sessionStorage.setItem('lca_portal_session', JSON.stringify(sessionData));

      await carregarDadosSessao(colab.id, colab.nome, colab.escritorio_id);
      toast.success(`Bem-vindo, ${colab.nome.split(' ')[0]}!`);

    } catch (err: any) {
      reportError('Erro Login', err.message || 'Falha na autenticação.');
    } finally {
      setIsLoggingIn(false);
    }
  };

  const logout = () => {
    setSession(null);
    sessionStorage.removeItem('lca_portal_session');
    toast.info('Sessão do portal encerrada.');
  };

  if (!session) {
    return (
      <div className="login-wrapper">
        <motion.div 
          initial={{ opacity: 0, y: 20 }} 
          animate={{ opacity: 1, y: 0 }} 
          className="glass-panel" 
          style={{ 
            width: '100%', 
            maxWidth: '440px', 
            padding: '3rem', 
            textAlign: 'center', 
            background: 'rgba(255, 255, 255, 0.03)',
            backdropFilter: 'blur(8px)',
            border: '1px solid rgba(255, 255, 255, 0.1)',
            borderRadius: '24px',
            boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)'
          }}
        >
          <div style={{ 
            width: '80px', 
            height: '80px', 
            background: 'linear-gradient(135deg, var(--color-primary), #3b82f6)', 
            borderRadius: '20px', 
            margin: '0 auto 2rem', 
            display: 'flex', 
            alignItems: 'center', 
            justifyContent: 'center', 
            color: 'white',
            boxShadow: '0 10px 20px rgba(59, 130, 246, 0.3)'
          }}>
            <LogIn size={40} />
          </div>

          <h2 className="text-serif" style={{ color: 'white', fontSize: '2rem', marginBottom: '0.75rem' }}>Portal LCA</h2>
          <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '1rem', marginBottom: '2.5rem' }}>Acesso exclusivo para membros do escritório Lang Cardoso Advocacia.</p>

          <form onSubmit={handleLogin} style={{ textAlign: 'left' }}>
            <div style={{ marginBottom: '1.5rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.8)', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.75rem' }}>E-mail Institucional</label>
              <input 
                type="email" 
                value={loginInput} 
                onChange={(e) => setLoginInput(e.target.value)} 
                placeholder="seu.nome@langcardoso.adv.br" 
                style={{ 
                  width: '100%', 
                  background: 'rgba(255,255,255,0.05)', 
                  border: '1px solid rgba(255,255,255,0.1)', 
                  padding: '1rem', 
                  borderRadius: '12px',
                  color: 'white',
                  outline: 'none',
                  transition: 'border-color 0.2s'
                }} 
              />
            </div>

            <div style={{ marginBottom: '2.5rem' }}>
              <label style={{ display: 'block', color: 'rgba(255,255,255,0.8)', fontSize: '0.875rem', fontWeight: 500, marginBottom: '0.75rem' }}>Senha de Acesso</label>
              <input 
                type="password" 
                value={passwordInput} 
                onChange={(e) => setPasswordInput(e.target.value)} 
                placeholder="••••••••" 
                style={{ 
                  width: '100%', 
                  background: 'rgba(255,255,255,0.05)', 
                  border: '1px solid rgba(255,255,255,0.1)', 
                  padding: '1rem', 
                  borderRadius: '12px',
                  color: 'white',
                  outline: 'none',
                  transition: 'border-color 0.2s'
                }} 
              />
            </div>
            <button 
              className="btn-primary" 
              style={{ 
                width: '100%', 
                padding: '1rem', 
                fontWeight: 600, 
                fontSize: '1rem',
                borderRadius: '12px',
                background: 'linear-gradient(90deg, var(--color-primary), #3b82f6)',
                border: 'none',
                cursor: 'pointer'
              }} 
              disabled={isLoggingIn}
            >
              {isLoggingIn ? 'Autenticando...' : 'Acessar Portal'}
            </button>
          </form>

          <div style={{ marginTop: '2rem', textAlign: 'center' }}>
          <p style={{ fontSize: '0.75rem', color: 'rgba(255,255,255,0.4)', margin: 0 }}>
            © 2024 Lang Cardoso Advocacia. Todos os direitos reservados.
          </p>
          <button 
            onClick={() => window.location.href = '/login'}
            style={{ 
              marginTop: '1rem', 
              background: 'transparent', 
              border: 'none', 
              color: 'var(--color-primary)', 
              fontSize: '0.8rem', 
              cursor: 'pointer',
              textDecoration: 'underline',
              opacity: 0.8
            }}
          >
            Acesso Administrativo / Dashboard
          </button>
        </div>
      </motion.div>
    </div>
  );
}

  const now = new Date();
  const thirtyDaysFromNow = new Date();
  thirtyDaysFromNow.setDate(now.getDate() + 30);

  const parseLatamDate = (dateStr: string) => {
    if (!dateStr) return new Date();
    const parts = dateStr.split('/');
    if (parts.length === 3) {
      return new Date(parseInt(parts[2]), parseInt(parts[1]) - 1, parseInt(parts[0]));
    }
    return new Date(dateStr);
  };

  const atrasados = distribuicoes.filter(d => {
    const dDate = parseLatamDate(d.data);
    return (d.status.toLowerCase().includes('atrasado')) || 
           (d.status.toLowerCase().includes('pendente') && dDate < now);
  });

  const proximos30 = distribuicoes.filter(d => {
    const dDate = parseLatamDate(d.data);
    return d.status.toLowerCase().includes('pendente') && dDate >= now && dDate <= thirtyDaysFromNow;
  });

  const pipelineTotal = distribuicoes.filter(d => d.status.toLowerCase().includes('pendente'));

  const totalPipeline = pipelineTotal.reduce((sum, d) => sum + d.valor, 0);
  const totalProximos30 = proximos30.reduce((sum, d) => sum + d.valor, 0);
  const totalAtrasados = atrasados.reduce((sum, d) => sum + d.valor, 0);

  const metasConclusao = demandas.length > 0 ? (demandas.filter(t => t.concluida).length / demandas.length) * 100 : 0;

  return (
    <motion.div 
      initial="initial" 
      animate="in" 
      exit="out" 
      variants={pageVariants} 
      transition={pageTransition} 
      style={{ 
        minHeight: '100vh', 
        background: '#020617', 
        padding: '2rem 1rem' 
      }}
    >
      <div style={{ maxWidth: '1100px', margin: '0 auto', width: '100%' }}>
        <header style={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          marginBottom: '2.5rem', 
          background: 'rgba(255, 255, 255, 0.03)', 
          backdropFilter: 'blur(10px)',
          padding: '1.5rem 2rem', 
          borderRadius: '24px', 
          border: '1px solid rgba(255, 255, 255, 0.05)',
          boxShadow: '0 10px 30px rgba(0,0,0,0.2)' 
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '1.25rem' }}>
            <div style={{ width: '56px', height: '56px', borderRadius: '18px', overflow: 'hidden', border: '2px solid var(--color-primary)', background: '#1e293b' }}>
              <img 
                src={session.foto_url || `https://ui-avatars.com/api/?name=${encodeURIComponent(session.nome)}&background=1e293b&color=fff`} 
                alt={session.nome} 
                style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
              />
            </div>
