/**
 * Utility to safely extract error messages from unknown types.
 * Helps avoid unsafe 'as Error' casting.
 */

export interface AppError {
  message: string;
  code?: string;
  details?: string;
  hint?: string;
}

export function toAppError(error: unknown): AppError {
  // Handle Null/Undefined
  if (!error) {
    return { message: 'Ocorreu um erro desconhecido.' };
  }

  // Handle standard Error objects
  if (error instanceof Error) {
    return { message: error.message };
  }

  // Handle Supabase/Injected error objects
  const err = error as any;
  if (typeof err === 'object') {
    return {
      message: err.message || err.error_description || err.error || 'Erro inesperado do sistema.',
      code: err.code || err.status?.toString(),
      details: err.details,
      hint: err.hint,
    };
  }

  // Handle strings
  if (typeof error === 'string') {
    return { message: error };
  }

  return { message: 'Falha na comunicação com o servidor.' };
}

export function getErrorMessage(error: unknown): string {
  return toAppError(error).message;
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

/**
 * LCA CHAT - Supabase Edge Function: Webhook Evolution API
 * Responsável por receber as mensagens do WhatsApp (Evolution) e salvá-las no banco.
 * Para fazer deploy: npx supabase functions deploy lca-evolution-webhook
 */

console.log("Serviço de Webhook LCA iniciado!");

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: { 'Access-Control-Allow-Origin': '*' } })
  }

  try {
    const payload = await req.json();

    // 1. Connect Supabase Admin
    const supabaseAdmin = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? ''
    );

    // 2. Identify Instance and Office (Simplified/Fast)
    const { instance } = payload;
    let escritorioId = null;

    if (instance) {
      const { data: inst } = await supabaseAdmin
        .from('lca_chat_instancias')
        .select('escritorio_id')
        .eq('nome_instancia', instance)
        .maybeSingle();
      escritorioId = inst?.escritorio_id;
    }

    // 3. Log to Durable Queue (Fastest way to ensure 200 OK)
    const { data: logEntry, error: logError } = await supabaseAdmin
      .from('lca_webhook_logs')
      .insert([{
        escritorio_id: escritorioId,
        payload: payload,
        processed: false
      }])
      .select('id')
      .single();

    if (logError) throw logError;

    // 4. Background Processing (Fire and Forget)
    // In a real production, a DB Trigger or Cron would handle this.
    // Here we trigger the processing logic WITHOUT awaiting it to respond fast to the webhook.
    processWebhook(logEntry.id, payload, escritorioId, supabaseAdmin).catch(err => 
      console.error(`[Webhook Background Error] Log ${logEntry.id}:`, err)
    );

    return new Response(JSON.stringify({ success: true, log_id: logEntry.id }), { 
      headers: { 'Content-Type': 'application/json' },
      status: 200 
    });

  } catch (err) {
    console.error("Webhook Critical Error:", err);
    return new Response(String(err), { status: 500 });
  }
});

async function processWebhook(logId: string, payload: any, escritorioId: string | null, supabaseAdmin: any) {
  try {
    if (payload.event !== 'messages.upsert') return markProcessed(logId, true, supabaseAdmin);
    if (!escritorioId) return markProcessed(logId, false, supabaseAdmin, "Office not found");

    const { data } = payload;
    const msgData = data.message;
    if (msgData.key.fromMe) return markProcessed(logId, true, supabaseAdmin);

    const telefoneCliente = msgData.key.remoteJid.replace('@s.whatsapp.net', '').replace('@g.us', '');
    const textoMensagem = msgData.message?.conversation || msgData.message?.extendedTextMessage?.text || "[Mídia/Contato]";

    // 1. Get/Create Contact
    let { data: contato } = await supabaseAdmin.from('contatos').select('id, nome').eq('telefone', telefoneCliente).eq('escritorio_id', escritorioId).maybeSingle();
    if (!contato) {
      const { data: newC } = await supabaseAdmin.from('contatos').insert([{ escritorio_id: escritorioId, nome: msgData.pushName || telefoneCliente, telefone: telefoneCliente, etapa: 'leads' }]).select('id, nome').single();
      contato = newC;
    }

    // 2. Get/Create Thread
    let threadId = null;
    const { data: thread } = await supabaseAdmin.from('chat_threads').select('id').eq('escritorio_id', escritorioId).contains('participantes', [contato.id]).eq('status', 'aguardando').maybeSingle();

    if (thread) {
       threadId = thread.id;
    } else {
       const { data: newT } = await supabaseAdmin.from('chat_threads').insert([{ escritorio_id: escritorioId, nome: contato.nome, tipo: 'equipe', status: 'aguardando', participantes: [contato.id], ultima_mensagem: textoMensagem }]).select('id').single();
       threadId = newT.id;
    }

    // 3. Save Message
    await supabaseAdmin.from('chat_mensagens').insert([{
      thread_id: threadId,
      escritorio_id: escritorioId,
      autor_id: contato.id,
      autor_nome: contato.nome,
      mensagem: textoMensagem,
      lida: false
    }]);

    // 4. Update Thread Timestamp
    await supabaseAdmin.from('chat_threads').update({ ultima_mensagem: textoMensagem, ultima_mensagem_data: new Date().toISOString() }).eq('id', threadId);

    await markProcessed(logId, true, supabaseAdmin);
  } catch (err: any) {
    await markProcessed(logId, false, supabaseAdmin, err.message);
  }
}

async function markProcessed(id: string, success: boolean, supabaseAdmin: any, error?: string) {
  await supabaseAdmin.from('lca_webhook_logs').update({ 
    processed: success, 
    processed_at: new Date().toISOString(),
    error_message: error 
  }).eq('id', id);
}

import { serve } from "https://deno.land/std@0.168.0/http/server.ts"
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

/**
 * LCA GOOGLE REFRESH - Supabase Edge Function
 * Exchanges OAuth code for tokens and manages refresh cycles.
 */

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders })
  }

  try {
    const supabaseClient = createClient(
      Deno.env.get('SUPABASE_URL') ?? '',
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY') ?? '',
      { global: { headers: { Authorization: req.headers.get('Authorization')! } } }
    )

    // Identify the user making the request
    const { data: { user }, error: userError } = await supabaseClient.auth.getUser()
    if (userError || !user) return new Response(JSON.stringify({ error: 'Unauthorized' }), { status: 401, headers: corsHeaders })

    // Get the colaborador entry to find the escritorio_id
    const { data: colab } = await supabaseClient
      .from('colaboradores')
      .select('escritorio_id, email')
      .eq('email', user.email)
      .single()

    if (!colab) return new Response(JSON.stringify({ error: 'Colaborador not found' }), { status: 404, headers: corsHeaders })

    const { code, refresh } = await req.json()
    const GOOGLE_CLIENT_ID = Deno.env.get('GOOGLE_CLIENT_ID')
    const GOOGLE_CLIENT_SECRET = Deno.env.get('GOOGLE_CLIENT_SECRET')
    const REDIRECT_URI = Deno.env.get('GOOGLE_REDIRECT_URI') || 'postmessage'

    // CASE 1: INITIAL AUTH (Exchange code for tokens)
    if (code) {
      const resp = await fetch('https://oauth2.googleapis.com/token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          code,
          client_id: GOOGLE_CLIENT_ID!,
          client_secret: GOOGLE_CLIENT_SECRET!,
          redirect_uri: REDIRECT_URI,
          grant_type: 'authorization_code',
          access_type: 'offline', // Critical for refresh_token
          prompt: 'consent'
        })
      });

      const data = await resp.json();
      if (!resp.ok) throw new Error(data.error_description || data.error || 'Google exchange failed');

      // Save the refresh token permanently
      if (data.refresh_token) {
        await supabaseClient.from('lca_google_auth').upsert({
          escritorio_id: colab.escritorio_id,
          email: colab.email,
          refresh_token: data.refresh_token,
          access_token: data.access_token,
          expires_at: new Date(Date.now() + data.expires_in * 1000).toISOString()
        }, { onConflict: 'escritorio_id, email' });
      }

      return new Response(JSON.stringify({ access_token: data.access_token }), { 
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200 
      });
    }

    // CASE 2: REFRESH TOKEN (Exchange refresh_token for new access_token)
    if (refresh) {
      const { data: authData } = await supabaseClient
        .from('lca_google_auth')
        .select('*')
        .eq('escritorio_id', colab.escritorio_id)
        .eq('email', colab.email)
        .single();

      if (!authData) return new Response(JSON.stringify({ error: 'No refresh token available' }), { status: 400, headers: corsHeaders });

      const resp = await fetch('https://oauth2.googleapis.com/token', {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: new URLSearchParams({
          client_id: GOOGLE_CLIENT_ID!,
          client_secret: GOOGLE_CLIENT_SECRET!,
          refresh_token: authData.refresh_token,
          grant_type: 'refresh_token'
        })
      });

      const data = await resp.json();
      if (!resp.ok) throw new Error('Token refresh failed');

      // Update the access token
      await supabaseClient.from('lca_google_auth').update({
        access_token: data.access_token,
        expires_at: new Date(Date.now() + data.expires_in * 1000).toISOString(),
        updated_at: new Date().toISOString()
      }).eq('id', authData.id);

      return new Response(JSON.stringify({ access_token: data.access_token }), { 
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200 
      });
    }

    return new Response(JSON.stringify({ error: 'Invalid request' }), { status: 400, headers: corsHeaders });

  } catch (err: any) {
    console.error("Google Refresh Error:", err);
    return new Response(JSON.stringify({ error: err.message }), { status: 500, headers: corsHeaders });
  }
})
